   142→/* ---------- Urgency Legend ---------- */
   143→
   144→function UrgencyLegend() {
   145→  const entries = [
   146→    { key: "critical", label: "Critical", desc: "Breaking changes, security patches" },
   147→    { key: "high", label: "High", desc: "Significant API changes, deprecations" },
   148→    { key: "medium", label: "Medium", desc: "Notable changes worth reviewing" },
   149→    { key: "low", label: "Low", desc: "Routine updates, dependency bumps" },
   150→  ] as const;
