     3→import (
     4→	"context"
     5→	"encoding/json"
     6→	"fmt"
     7→	"net/http"
     8→	"os"
     9→	"time"
    10→)
    11→
    12→const defaultGitHubAPIURL = "https://api.github.com"
    13→
    14→// ghRelease represents a single release from the GitHub REST API.
    15→type ghRelease struct {
    16→	TagName     string `json:"tag_name"`
    17→	Body        string `json:"body"`
    18→	HTMLURL     string `json:"html_url"`
    19→	PublishedAt string `json:"published_at"`
    20→	Prerelease  bool   `json:"prerelease"`
    21→	Draft       bool   `json:"draft"`
    22→}
    23→
    24→// GitHubSource polls the GitHub REST API for repository releases.
    25→type GitHubSource struct {
    26→	client     *http.Client
    27→	repository string
    28→	baseURL    string
    29→	sourceID   string
    30→}
    31→
    32→func NewGitHubSource(client *http.Client, repository string, sourceID string) *GitHubSource {
    33→	return &GitHubSource{
    34→		client:     client,
    35→		repository: repository,
    36→		baseURL:    defaultGitHubAPIURL,
    37→		sourceID:   sourceID,
    38→	}
    39→}
    40→
    41→func (s *GitHubSource) Name() string    { return "github" }
    42→func (s *GitHubSource) SourceID() string { return s.sourceID }
    43→
    44→func (s *GitHubSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    45→	url := fmt.Sprintf("%s/repos/%s/releases?per_page=30", s.baseURL, s.repository)
    46→
    47→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
    48→	if err != nil {
    49→		return nil, fmt.Errorf("create request: %w", err)
    50→	}
    51→	req.Header.Set("Accept", "application/vnd.github+json")
    52→
    53→	if token := os.Getenv("GITHUB_TOKEN"); token != "" {
    54→		req.Header.Set("Authorization", "Bearer "+token)
    55→	}
    56→
    57→	resp, err := s.client.Do(req)
    58→	if err != nil {
    59→		return nil, fmt.Errorf("fetch releases: %w", err)
    60→	}
    61→	defer resp.Body.Close()
    62→
    63→	if resp.StatusCode != http.StatusOK {
    64→		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
    65→	}
    66→
    67→	var releases []ghRelease
    68→	if err := json.NewDecoder(resp.Body).Decode(&releases); err != nil {
    69→		return nil, fmt.Errorf("decode releases: %w", err)
    70→	}
    71→
    72→	results := make([]IngestionResult, 0, len(releases))
    73→	for _, rel := range releases {
    74→		if rel.Draft {
    75→			continue
    76→		}
    77→		if rel.TagName == "" {
    78→			continue
    79→		}
    80→
    81→		ts, _ := time.Parse(time.RFC3339, rel.PublishedAt)
    82→
    83→		prerelease := "false"
    84→		if rel.Prerelease {
    85→			prerelease = "true"
    86→		}
    87→
    88→		results = append(results, IngestionResult{
    89→			Repository: s.repository,
    90→			RawVersion: rel.TagName,
    91→			Changelog:  rel.Body,
    92→			Metadata: map[string]string{
    93→				"release_url": rel.HTMLURL,
    94→				"prerelease":  prerelease,
    95→			},
    96→			Timestamp: ts,
    97→		})
    98→	}
    99→	return results, nil
   100→}
