   878→func (s *PgStore) TriggerAgentRun(ctx context.Context, projectID, trigger, version string) (*models.AgentRun, error) {
   879→	var run models.AgentRun
   880→	err := s.pool.QueryRow(ctx,
   881→		`INSERT INTO agent_runs (project_id, trigger, version, status)
   882→		 VALUES ($1, $2, $3, 'pending')
   883→		 RETURNING id, project_id, trigger, COALESCE(version,''), status, created_at`,
   884→		projectID, trigger, nilIfEmpty(version),
   885→	).Scan(&run.ID, &run.ProjectID, &run.Trigger, &run.Version, &run.Status, &run.CreatedAt)
   886→	if err != nil {
   887→		return nil, fmt.Errorf("insert agent run: %w", err)
   888→	}
   889→
   890→	// Enqueue a River job to process the agent run, if river client is available.
   891→	if s.river != nil {
   892→		_, err = s.river.Insert(ctx, queue.AgentJobArgs{
   893→			AgentRunID: run.ID,
   894→			ProjectID:  projectID,
   895→			Version:    version,
   896→		}, nil)
   897→		if err != nil {
   898→			// If the agent worker isn't registered (missing LLM API key),
   899→			// mark the run as failed rather than returning an error.
   900→			if strings.Contains(err.Error(), "not registered") {
   901→				_, _ = s.pool.Exec(ctx,
   902→					`UPDATE agent_runs SET status = 'failed', error = $2, completed_at = NOW() WHERE id = $1`,
   903→					run.ID, "Agent worker not available — configure GOOGLE_API_KEY or OPENAI_API_KEY")
   904→				run.Status = "failed"
   905→				run.Error = "Agent worker not available — configure GOOGLE_API_KEY or OPENAI_API_KEY"
   906→				return &run, nil
   907→			}
   908→			return nil, fmt.Errorf("enqueue agent job: %w", err)
   909→		}
   910→	}
   911→
   912→	return &run, nil
   913→}
