     1→package api
     2→
     3→import (
     4→	"encoding/json"
     5→	"fmt"
     6→	"net/http"
     7→	"net/url"
     8→	"sync"
     9→	"time"
    10→)
    11→
    12→const discoverCacheTTL = 1 * time.Hour
    13→
    14→// DiscoverItem represents a single repository/image result from a discovery search.
    15→type DiscoverItem struct {
    16→	Name        string `json:"name"`
    17→	FullName    string `json:"full_name"`
    18→	Description string `json:"description"`
    19→	Stars       int    `json:"stars"`
    20→	Language    string `json:"language,omitempty"`
    21→	URL         string `json:"url"`
    22→	AvatarURL   string `json:"avatar_url,omitempty"`
    23→	Provider    string `json:"provider"`
    24→}
    25→
    26→type cachedResult struct {
    27→	items     []DiscoverItem
    28→	fetchedAt time.Time
    29→}
    30→
    31→// DiscoverHandler implements HTTP handlers for the /discover resource.
    32→type DiscoverHandler struct {
    33→	client       *http.Client
    34→	githubURL    string
    35→	dockerHubURL string
    36→	mu           sync.Mutex
    37→	cache        map[string]cachedResult
    38→}
    39→
    40→// NewDiscoverHandler returns a new DiscoverHandler. Empty URL strings default
    41→// to the real GitHub / Docker Hub API base URLs.
    42→func NewDiscoverHandler(client *http.Client, githubURL, dockerHubURL string) *DiscoverHandler {
    43→	if githubURL == "" {
    44→		githubURL = "https://api.github.com"
    45→	}
    46→	if dockerHubURL == "" {
    47→		dockerHubURL = "https://hub.docker.com"
    48→	}
    49→	return &DiscoverHandler{
    50→		client:       client,
    51→		githubURL:    githubURL,
    52→		dockerHubURL: dockerHubURL,
    53→		cache:        make(map[string]cachedResult),
    54→	}
    55→}
    56→
    57→func (h *DiscoverHandler) getCached(key string) ([]DiscoverItem, bool) {
    58→	h.mu.Lock()
    59→	defer h.mu.Unlock()
    60→	c, ok := h.cache[key]
    61→	if !ok {
    62→		return nil, false
    63→	}
    64→	if time.Since(c.fetchedAt) > discoverCacheTTL {
    65→		delete(h.cache, key)
    66→		return nil, false
    67→	}
    68→	return c.items, true
    69→}
    70→
    71→func (h *DiscoverHandler) setCache(key string, items []DiscoverItem) {
    72→	h.mu.Lock()
    73→	defer h.mu.Unlock()
    74→	h.cache[key] = cachedResult{items: items, fetchedAt: time.Now()}
    75→}
    76→
    77→// GitHub handles GET /discover/github — searches GitHub repositories.
    78→func (h *DiscoverHandler) GitHub(w http.ResponseWriter, r *http.Request) {
    79→	q := r.URL.Query().Get("q")
    80→	language := r.URL.Query().Get("language")
    81→
    82→	cacheKey := fmt.Sprintf("github:%s:%s", q, language)
    83→	if items, ok := h.getCached(cacheKey); ok {
    84→		RespondJSON(w, r, http.StatusOK, items)
    85→		return
    86→	}
    87→
    88→	// Approximate GitHub Trending: search for repos with recent star activity.
    89→	// Default query filters to repos created in the last 7 days, sorted by stars.
    90→	since := time.Now().AddDate(0, 0, -7).Format("2006-01-02")
    91→	searchQ := q
    92→	if searchQ == "" {
    93→		searchQ = fmt.Sprintf("created:>%s stars:>10", since)
    94→	}
    95→	if language != "" {
    96→		searchQ = fmt.Sprintf("%s language:%s", searchQ, language)
    97→	}
    98→
    99→	u, _ := url.Parse(h.githubURL + "/search/repositories")
   100→	params := url.Values{}
   101→	params.Set("q", searchQ)
   102→	params.Set("sort", "stars")
   103→	params.Set("order", "desc")
   104→	params.Set("per_page", "25")
   105→	u.RawQuery = params.Encode()
   106→
   107→	req, err := http.NewRequestWithContext(r.Context(), http.MethodGet, u.String(), nil)
   108→	if err != nil {
   109→		RespondError(w, r, http.StatusInternalServerError, "request_error", "failed to build GitHub request")
   110→		return
   111→	}
   112→	resp, err := h.client.Do(req)
   113→	if err != nil {
   114→		RespondError(w, r, http.StatusBadGateway, "upstream_error", "failed to reach GitHub API")
   115→		return
   116→	}
   117→	defer resp.Body.Close()
   118→
   119→	if resp.StatusCode != http.StatusOK {
   120→		RespondError(w, r, http.StatusBadGateway, "upstream_error", fmt.Sprintf("GitHub API returned %d", resp.StatusCode))
   121→		return
   122→	}
   123→
   124→	var ghResp struct {
   125→		Items []struct {
   126→			Name        string `json:"name"`
   127→			FullName    string `json:"full_name"`
   128→			Description string `json:"description"`
   129→			Stars       int    `json:"stargazers_count"`
   130→			Language    string `json:"language"`
   131→			HTMLURL     string `json:"html_url"`
   132→			Owner       struct {
   133→				AvatarURL string `json:"avatar_url"`
   134→			} `json:"owner"`
   135→		} `json:"items"`
   136→	}
   137→	if err := json.NewDecoder(resp.Body).Decode(&ghResp); err != nil {
   138→		RespondError(w, r, http.StatusInternalServerError, "decode_error", "failed to parse GitHub response")
   139→		return
   140→	}
   141→
   142→	items := make([]DiscoverItem, 0, len(ghResp.Items))
   143→	for _, repo := range ghResp.Items {
   144→		items = append(items, DiscoverItem{
   145→			Name:        repo.Name,
   146→			FullName:    repo.FullName,
   147→			Description: repo.Description,
   148→			Stars:       repo.Stars,
   149→			Language:    repo.Language,
   150→			URL:         repo.HTMLURL,
   151→			AvatarURL:   repo.Owner.AvatarURL,
   152→			Provider:    "github",
   153→		})
   154→	}
   155→
   156→	h.setCache(cacheKey, items)
   157→	RespondJSON(w, r, http.StatusOK, items)
   158→}
   159→
   160→// DockerHub handles GET /discover/dockerhub — searches Docker Hub repositories.
   161→func (h *DiscoverHandler) DockerHub(w http.ResponseWriter, r *http.Request) {
   162→	q := r.URL.Query().Get("q")
   163→	if q == "" {
   164→		q = "nginx"
   165→	}
   166→
