    10→// TodosStore defines the data access interface for TODO operations.
    11→type TodosStore interface {
    12→	ListTodos(ctx context.Context, status string, page, perPage int, aggregated bool) ([]models.Todo, int, error)
    13→	GetTodo(ctx context.Context, id string) (*models.Todo, error)
    14→	AcknowledgeTodo(ctx context.Context, id string, cascade bool) error
    15→	ResolveTodo(ctx context.Context, id string, cascade bool) error
    16→	ReopenTodo(ctx context.Context, id string) error
    17→}
    18→
    19→// TodosHandler handles HTTP requests for release TODOs.
    20→type TodosHandler struct {
    21→	store     TodosStore
    22→	publicURL string
    23→}
    24→
    25→// NewTodosHandler creates a new TodosHandler.
    26→func NewTodosHandler(store TodosStore, publicURL string) *TodosHandler {
    27→	return &TodosHandler{store: store, publicURL: publicURL}
    28→}
    29→
    30→// List returns a paginated list of TODOs, optionally filtered by status.
    31→func (h *TodosHandler) List(w http.ResponseWriter, r *http.Request) {
    32→	page, perPage := ParsePagination(r)
    33→	status := r.URL.Query().Get("status")
    34→	aggregated := r.URL.Query().Get("aggregated") == "true"
    35→
    36→	todos, total, err := h.store.ListTodos(r.Context(), status, page, perPage, aggregated)
    37→	if err != nil {
    38→		RespondError(w, r, http.StatusInternalServerError, "internal_error", err.Error())
    39→		return
    40→	}
    41→	if todos == nil {
    42→		todos = []models.Todo{}
    43→	}
    44→	RespondList(w, r, http.StatusOK, todos, page, perPage, total)
    45→}
    46→
    47→// Get returns a single TODO by ID.
    48→func (h *TodosHandler) Get(w http.ResponseWriter, r *http.Request) {
    49→	id := r.PathValue("id")
    50→	todo, err := h.store.GetTodo(r.Context(), id)
    51→	if err != nil {
    52→		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
    53→		return
    54→	}
    55→	RespondJSON(w, r, http.StatusOK, todo)
    56→}
    57→
    58→// Acknowledge marks a TODO as acknowledged. Supports both PATCH (API) and GET with redirect (notification links).
    59→func (h *TodosHandler) Acknowledge(w http.ResponseWriter, r *http.Request) {
    60→	id := r.PathValue("id")
    61→	cascade := r.URL.Query().Get("cascade") == "true"
    62→	if err := h.store.AcknowledgeTodo(r.Context(), id, cascade); err != nil {
    63→		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
    64→		return
    65→	}
    66→
    67→	// If redirect=true, send 302 to the frontend todo page.
    68→	if r.URL.Query().Get("redirect") == "true" && h.publicURL != "" {
    69→		http.Redirect(w, r, h.publicURL+"/todo", http.StatusFound)
    70→		return
    71→	}
    72→
    73→	RespondJSON(w, r, http.StatusOK, map[string]string{"status": "acknowledged"})
    74→}
    75→
    76→// Resolve marks a TODO as resolved. Supports both PATCH (API) and GET with redirect (notification links).
    77→func (h *TodosHandler) Resolve(w http.ResponseWriter, r *http.Request) {
    78→	id := r.PathValue("id")
    79→	cascade := r.URL.Query().Get("cascade") == "true"
    80→	if err := h.store.ResolveTodo(r.Context(), id, cascade); err != nil {
    81→		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
    82→		return
    83→	}
    84→
    85→	// If redirect=true, send 302 to the frontend todo page.
    86→	if r.URL.Query().Get("redirect") == "true" && h.publicURL != "" {
    87→		http.Redirect(w, r, h.publicURL+"/todo", http.StatusFound)
    88→		return
    89→	}
    90→
    91→	RespondJSON(w, r, http.StatusOK, map[string]string{"status": "resolved"})
    92→}
    93→
    94→// Reopen marks a TODO as pending again, clearing acknowledged/resolved timestamps.
    95→func (h *TodosHandler) Reopen(w http.ResponseWriter, r *http.Request) {
    96→	id := r.PathValue("id")
    97→	if err := h.store.ReopenTodo(r.Context(), id); err != nil {
    98→		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
    99→		return
   100→	}
   101→
   102→	RespondJSON(w, r, http.StatusOK, map[string]string{"status": "pending"})
   103→}
