	river  RiverInserter
}

// RiverInserter is the minimal interface for enqueuing River jobs.
type RiverInserter interface {
	Insert(ctx context.Context, args interface{ Kind() string }, opts *interface{}) (*interface{}, error)
}

// NewOnboardHandler returns a new OnboardHandler.
func NewOnboardHandler(store OnboardStore) *OnboardHandler {
