   426→func (s *Scanner) doRequest(ctx context.Context, url string, target any) error {
   427→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
   428→	if err != nil {
   429→		return fmt.Errorf("create request: %w", err)
   430→	}
   431→	req.Header.Set("Accept", "application/vnd.github+json")
   432→	if s.token != "" {
   433→		req.Header.Set("Authorization", "Bearer "+s.token)
   434→	}
   435→
   436→	resp, err := s.client.Do(req)
   437→	if err != nil {
   438→		return fmt.Errorf("execute request: %w", err)
   439→	}
   440→	defer resp.Body.Close()
   441→
   442→	if resp.StatusCode != http.StatusOK {
   443→		return fmt.Errorf("GitHub API returned %d for %s", resp.StatusCode, url)
   444→	}
   445→	return json.NewDecoder(resp.Body).Decode(target)
   446→}
