   478→func (s *Scanner) getFileContent(ctx context.Context, owner, repo, path string) (string, error) {
   479→	var result struct {
   480→		Content  string `json:"content"`
   481→		Encoding string `json:"encoding"`
   482→	}
   483→	url := fmt.Sprintf("%s/repos/%s/%s/contents/%s", s.baseURL, owner, repo, path)
   484→	if err := s.doRequest(ctx, url, &result); err != nil {
   485→		return "", err
   486→	}
   487→	if result.Encoding == "base64" {
   488→		// GitHub base64 content may contain newlines
   489→		cleaned := strings.ReplaceAll(result.Content, "\n", "")
   490→		decoded, err := base64.StdEncoding.DecodeString(cleaned)
   491→		if err != nil {
   492→			return "", fmt.Errorf("decode base64: %w", err)
   493→		}
   494→		return string(decoded), nil
   495→	}
   496→	return result.Content, nil
