   606→
   607→```go
   608→package onboard
   609→
   610→import (
   611→	"context"
   612→	"encoding/json"
   613→	"fmt"
   614→	"strings"
   615→
   616→	"github.com/sentioxyz/changelogue/internal/models"
   617→	"google.golang.org/genai"
   618→)
   619→
   620→const extractionPrompt = `You are a dependency extraction agent. Given the contents of dependency/manifest files from a software project, extract all direct dependencies (not dev dependencies or build tools).
   621→
   622→For each dependency, return:
   623→- name: the package/library name
   624→- version: the version constraint or pinned version
   625→- ecosystem: one of "go", "npm", "pypi", "cargo", "rubygems", "maven", "gradle", "docker", "other"
   626→- upstream_repo: your best guess at the canonical GitHub repository URL (e.g., "github.com/gorilla/mux"). Use the format "github.com/owner/repo" without https://.
   627→- provider: the Changelogue provider to use for release tracking. Use "github" for repos with GitHub releases, "dockerhub" for Docker images, "gitlab" for GitLab repos, "ecr_public" for AWS ECR images. When unsure, default to "github".
   628→
   629→Return ONLY a JSON array. No explanations, no markdown formatting.`
   630→
   631→// DependencyExtractor calls Gemini to extract dependencies from file contents.
   632→type DependencyExtractor struct {
   633→	client *genai.Client
   634→	model  string
   635→}
   636→
   637→// NewDependencyExtractor creates a new extractor. apiKey and model are required.
   638→func NewDependencyExtractor(ctx context.Context, apiKey, model string) (*DependencyExtractor, error) {
   639→	if apiKey == "" {
   640→		return nil, fmt.Errorf("GOOGLE_API_KEY is required for dependency extraction")
   641→	}
   642→	if model == "" {
   643→		model = "gemini-2.5-flash"
   644→	}
   645→	client, err := genai.NewClient(ctx, &genai.ClientConfig{
   646→		APIKey: apiKey,
   647→	})
   648→	if err != nil {
   649→		return nil, fmt.Errorf("create genai client: %w", err)
   650→	}
   651→	return &DependencyExtractor{client: client, model: model}, nil
   652→}
   653→
   654→// Extract sends dependency file contents to Gemini and returns parsed dependencies.
   655→func (e *DependencyExtractor) Extract(ctx context.Context, files []DependencyFile) ([]models.ScannedDependency, error) {
   656→	if len(files) == 0 {
   657→		return []models.ScannedDependency{}, nil
   658→	}
   659→
   660→	prompt := BuildExtractionPrompt(files)
   661→
   662→	result, err := e.client.Models.GenerateContent(ctx, e.model, genai.Text(prompt), nil)
   663→	if err != nil {
   664→		return nil, fmt.Errorf("gemini generate: %w", err)
   665→	}
   666→
   667→	if len(result.Candidates) == 0 || len(result.Candidates[0].Content.Parts) == 0 {
   668→		return nil, fmt.Errorf("gemini returned no content")
   669→	}
   670→
   671→	text := result.Candidates[0].Content.Parts[0].Text
   672→	return ParseDependencies([]byte(text))
   673→}
   674→
   675→// BuildExtractionPrompt constructs the prompt with file contents.
   676→func BuildExtractionPrompt(files []DependencyFile) string {
   677→	var b strings.Builder
   678→	b.WriteString(extractionPrompt)
   679→	b.WriteString("\n\n--- FILES ---\n")
   680→	for _, f := range files {
   681→		fmt.Fprintf(&b, "\n### %s\n```\n%s\n```\n", f.Path, f.Content)
   682→	}
   683→	return b.String()
   684→}
   685→
   686→// ParseDependencies parses the LLM response into ScannedDependency structs.
   687→// Handles raw JSON arrays and markdown-fenced JSON.
   688→func ParseDependencies(raw []byte) ([]models.ScannedDependency, error) {
   689→	text := strings.TrimSpace(string(raw))
   690→
   691→	// Strip markdown code fences if present
   692→	if strings.HasPrefix(text, "```") {
   693→		lines := strings.Split(text, "\n")
   694→		// Remove first and last lines (the fence markers)
   695→		if len(lines) >= 2 {
   696→			lines = lines[1 : len(lines)-1]
   697→			// Remove trailing fence if still present
   698→			if len(lines) > 0 && strings.HasPrefix(strings.TrimSpace(lines[len(lines)-1]), "```") {
   699→				lines = lines[:len(lines)-1]
   700→			}
   701→			text = strings.Join(lines, "\n")
   702→		}
   703→	}
   704→
   705→	var deps []models.ScannedDependency
   706→	if err := json.Unmarshal([]byte(text), &deps); err != nil {
   707→		return nil, fmt.Errorf("parse dependencies JSON: %w\nraw: %s", err, text)
   708→	}
   709→	return deps, nil
   710→}
   711→```
